use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use aiken/interval

pub type Datum {
  owner: VerificationKeyHash,
  expiry: Int,
}

validator owner_before_expiry {
  spend(datum: Option<Datum>, _redeemer, _own_ref, self) {
    expect Some(Datum { owner, expiry }) = datum
    let signed = list.has(self.extra_signatories, owner)
    let in_time = interval.is_entirely_before(self.validity_range, expiry)
    signed && in_time
  }
}

use aiken/interval

validator timed_mint {
  mint(_redeemer, _policy_id, self) {
    let start = 1_700_000_000_000
    let end = 1_710_000_000_000
    interval.contains(self.validity_range, start) && interval.contains(self.validity_range, end)
  }
}

use cardano/transaction

pub type PriceDatum {
  price: Int,
}

validator datum_hash_spend {
  spend(_datum, _redeemer, own_ref, self) {
    let own_input = transaction.resolve_input(self.inputs, own_ref)
    expect InlineDatum(raw) | DatumHash(hash) = own_input.output.datum
    // Using find_datum to retrieve from datums map by hash
    expect Some(raw_datum) = transaction.find_datum(self.datums, hash)
    expect PriceDatum { price } = raw_datum
    price > 0
  }
}

use aiken/collection/list
use cardano/assets
use cardano/transaction

validator preserve_lovelace {
  spend(_datum, _redeemer, own_ref, self) {
    let own_input = transaction.resolve_input(self.inputs, own_ref)
    let own_lovelace = assets.lovelace_of(own_input.output.value)
    let continuing = transaction.find_script_outputs(self.outputs, own_ref)
    let out_lovelace =
      list.foldl(
        continuing,
        0,
        fn(o, acc) { acc + assets.lovelace_of(o.value) },
      )
    out_lovelace >= own_lovelace
  }
}

use aiken/collection/list
use cardano/transaction.{find_input, TransactionId}

validator allowlisted_tx(ref_oref: OutputReference) {
  spend(_datum, _redeemer, _own_ref, self) {
    expect Some(ref_input) = find_input(self.reference_inputs, ref_oref)
    expect allowed_ids: List<TransactionId> = ref_input.output.datum
    list.has(allowed_ids, self.id)
  }
}

