use cardano/assets
use cardano/transaction

pub type OracleDatum {
  price: Int,
}

pub type Datum {
  oracle_ref: transaction.OutputReference,
}

validator price_check {
  spend(datum: Option<Datum>, _redeemer, _own_ref, self) {
    expect Some(Datum { oracle_ref }) = datum
    expect Some(oracle_input) =
      transaction.find_input(self.reference_inputs, oracle_ref)
    expect Some(raw) =
      transaction.find_datum(self.datums, oracle_input.output.datum)
    expect OracleDatum { price } = raw
    expect Some(payment_output) = list.at(self.outputs, 0)
    assets.lovelace_of(payment_output.value) >= price
  }
}

use aiken/interval

validator timed_mint(open_time: Int, close_time: Int) {
  mint(_redeemer, _policy_id, self) {
    interval.contains(self.validity_range, open_time) || (
      interval.contains(self.validity_range, close_time) |> fn(_) { False }
    )
    // Correct approach: ensure validity_range is entirely within [open, close]
    interval.is_entirely_after(self.validity_range, open_time) && interval.is_entirely_before(
      self.validity_range,
      close_time,
    )
  }
}

use aiken/collection/list
use aiken/crypto.{VerificationKeyHash}
use cardano/transaction.{OutputReference}
use cardano/transaction

validator allowlisted_spend(allowlist_ref: OutputReference) {
  spend(_datum, redeemer: VerificationKeyHash, _own_ref, self) {
    expect Some(ref_input) =
      transaction.find_input(self.reference_inputs, allowlist_ref)
    expect Some(raw) =
      transaction.find_datum(self.datums, ref_input.output.datum)
    expect allowed: List<VerificationKeyHash> = raw
    list.has(allowed, redeemer)
  }
}

use cardano/assets

validator no_mint {
  spend(_datum, _redeemer, _own_ref, self) {
    // An empty mint Value contains only lovelace = 0
    // assets.lovelace_of on a purely-lovelace Value returns its lovelace amount;
    // for the mint field, an empty mint has lovelace_of == 0 and no other assets.
    self.mint == assets.zero
  }
}

use aiken/interval

validator hard_deadline(hard_expiry: Int) {
  spend(_datum, _redeemer, _own_ref, self) {
    interval.is_entirely_before(self.validity_range, hard_expiry)
  }
}
